import React, { useState } from "react";
import "./App.css";

function App() {
  // -----------------------------
  // STATES
  // -----------------------------
  const [idea, setIdea] = useState("");
  const [html, setHtml] = useState("");
  const [loading, setLoading] = useState(false);
  const [template, setTemplate] = useState("generic");

  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [projects, setProjects] = useState([]);

  // -----------------------------
  // LOGIN
  // -----------------------------
  const login = async () => {
    try {
      const res = await fetch("http://127.0.0.1:8000/login", {
        method: "POST",
        headers: {
          "Content-Type": "application/json"
        },
        body: JSON.stringify({
          email,
          password
        })
      });

      const data = await res.json();

      if (data.access_token) {
        localStorage.setItem("token", data.access_token);
        alert("Login successful ✅");
      } else {
        alert("Login failed ❌");
      }
    } catch (err) {
      alert("Login error");
    }
  };

  // -----------------------------
  // GENERATE WEBSITE (WITH TOKEN)
  // -----------------------------
  const generateWebsite = async () => {
    if (!idea) return alert("Enter a business idea");

    const token = localStorage.getItem("token");

    if (!token) {
      return alert("Please login first!");
    }

    setLoading(true);

    try {
      const res = await fetch("http://127.0.0.1:8000/generate-ai", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "Authorization": `Bearer ${token}`
        },
        body: JSON.stringify({
          idea,
          template
        })
      });

      const data = await res.json();

      if (data.error) {
        alert("Error: " + data.error);
      } else {
        setHtml(data.html);
      }
    } catch (err) {
      alert("Something went wrong");
    }

    setLoading(false);
  };

  // -----------------------------
  // FETCH PROJECTS
  // -----------------------------
  const fetchProjects = async () => {
    const token = localStorage.getItem("token");

    if (!token) {
      return alert("Login first!");
    }

    try {
      const res = await fetch("http://127.0.0.1:8000/projects", {
        headers: {
          "Authorization": `Bearer ${token}`
        }
      });

      const data = await res.json();
      setProjects(data);
    } catch (err) {
      alert("Error fetching projects");
    }
  };

  // -----------------------------
  // DOWNLOAD
  // -----------------------------
  const downloadWebsite = () => {
    if (!html) return alert("Generate a website first!");

    const blob = new Blob([html], { type: "text/html" });
    const link = document.createElement("a");

    link.href = URL.createObjectURL(blob);
    link.download = "website.html";
    link.click();
  };

  // -----------------------------
  // UI
  // -----------------------------
  return (
  <div className="container">
    <h1>🚀 AI Website Builder</h1>

    {/* LOGIN */}
    <div className="login-card">
      <h3>Login</h3>

      <input
        type="text"
        placeholder="Email"
        onChange={(e) => setEmail(e.target.value)}
      />

      <input
        type="password"
        placeholder="Password"
        onChange={(e) => setPassword(e.target.value)}
      />

      <button onClick={login}>Login</button>
    </div>

    {/* GENERATOR */}
    <div className="card">
      <input
        type="text"
        placeholder="Enter your business idea..."
        value={idea}
        onChange={(e) => setIdea(e.target.value)}
      />

      <select
        value={template}
        onChange={(e) => setTemplate(e.target.value)}
      >
        <option value="generic">Generic</option>
        <option value="modern">Modern</option>
        <option value="luxury">Luxury</option>
      </select>

      <div className="button-group">
        <button onClick={generateWebsite}>
          {loading ? "Generating..." : "Generate Website"}
        </button>

        <button className="download-btn" onClick={downloadWebsite}>
          ⬇ Download
        </button>

        <button onClick={fetchProjects}>
          📂 My Projects
        </button>
      </div>
    </div>

    {/* PROJECTS */}
    <div className="card">
      <h3>My Projects</h3>

      {projects.length === 0 ? (
        <p>No projects yet</p>
      ) : (
        projects.map((p) => (
          <div key={p.id}>
            <strong>{p.name}</strong>
          </div>
        ))
      )}
    </div>

    {/* PREVIEW */}
    <h2>Preview</h2>

    <div className="preview">
      {loading ? (
        <div className="loader"></div>
      ) : (
        <iframe title="preview" srcDoc={html} />
      )}
    </div>
  </div>
);
}

export default App;
